  `pasta_id` int(100) unsigned NOT NULL AUTO_INCREMENT,
  `usuario_id` int(100) unsigned DEFAULT NULL,
  `nome` varchar(20) DEFAULT NULL,
  `pasta_ordem` int(100) unsigned DEFAULT NULL,
  PRIMARY KEY (`pasta_id`),
  KEY `usuario_id` (`usuario_id`),
  CONSTRAINT `pasta_fk` FOREIGN KEY (`usuario_id`) REFERENCES `usuarios` (`usuario_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS perfil;

CREATE TABLE `perfil` (
  `perfil_id` int(100) unsigned NOT NULL AUTO_INCREMENT,
  `perfil_nome` varchar(255) DEFAULT NULL,
  `perfil_descricao` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`perfil_id`),
  UNIQUE KEY `perfil_id` (`perfil_id`)
) ENGINE=InnoDB AUTO_INCREMENT=16 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS perfil_acesso;

CREATE TABLE `perfil_acesso` (
  `perfil_acesso_id` int(100) unsigned NOT NULL AUTO_INCREMENT,
  `perfil_acesso_perfil` int(100) unsigned NOT NULL,
