) ENGINE=InnoDB AUTO_INCREMENT=63 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS perfil_usuario;

CREATE TABLE `perfil_usuario` (
  `perfil_usuario_usuario` int(100) unsigned NOT NULL,
