  `pratica_criterio_id` int(100) unsigned NOT NULL AUTO_INCREMENT,
  `pratica_criterio_modelo` int(100) unsigned DEFAULT NULL,
  `pratica_criterio_numero` int(11) DEFAULT NULL,
