  `pratica_criterio_orientacao` text DEFAULT NULL,
  `pratica_criterio_resultado` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`pratica_criterio_id`),
  KEY `pratica_criterio_modelo` (`pratica_criterio_modelo`),
  CONSTRAINT `pratica_criterio_fk` FOREIGN KEY (`pratica_criterio_modelo`) REFERENCES `pratica_modelo` (`pratica_modelo_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=105 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

	<li style=\"text-align: justify;\">Os referenciais comparativos pertinentes, que forem apresentados, devem ser compatĂ­veis com os padrĂ”es gerenciais descritos em 1.4a para permitir a avaliaĂ§ĂŁo da competitividade.</li>
	<li style=\"text-align: justify;\">A competitividade do resultado em um tema pode ser avaliada por meio de indicadores com referenciais comparativos diferentes daqueles utilizados para avaliar a melhoria no mesmo tema.</li>
	<li style=\"text-align: justify;\">Os nĂ­veis de desempenho ou melhorias esperadas, que expressam os principais requisitos de partes interessadas, devem ser compatĂ­veis com os padrĂ”es descritos em 1.3C, 3.1 B, 4.1A, 4.2B, 6.3B, 7.1 A, 7.2B E 7.3A.</li>
	<li style=\"text-align: justify;\">Podem ser apresentados indicadores, entre os relevantes, sem referencial comparativo pertinente, quando o resultado nĂŁo for comparĂĄvel; e sem requisito de parte interessada, quando nĂŁo refletir necessidades e expectativas de partes interessadas, se eles forem relevantes para avaliar a melhoria.</li>
	<li style=\"text-align: justify;\">No caso de unidade autĂŽnoma, em indicadores cujo levantamento de resultados Ă© realizado somente no nĂ­vel corporativo, demonstrar a contribuiĂ§ĂŁo da unidade para o resultado alcanĂ§ado.</li>
</ol>
