INSERT INTO pratica_criterio VALUES
('9','2','1','LideranĂ§a','110','Este critĂ©rio examina a governanĂ§a pĂșblica e a governabilidade da organizaĂ§ĂŁo, incluindo aspectos relativos Ă  transparĂȘncia, eqĂŒidade, prestaĂ§ĂŁo de contas e responsabilidade corporativa. TambĂ©m examina como Ă© exercida a lideranĂ§a, incluindo temas como mudanĂ§a cultural e implementaĂ§ĂŁo do sistema de gestĂŁo da organizaĂ§ĂŁo. O critĂ©rio aborda a anĂĄlise do desempenho da organizaĂ§ĂŁo enfatizando a comparaĂ§ĂŁo com o desempenho de outras organizaĂ§Ă”es e a avaliaĂ§ĂŁo do ĂȘxito das estratĂ©gias.',NULL,'0'),
('10','2','2','EstratĂ©gias e Planos','60','Este critĂ©rio examina como a organizaĂ§ĂŁo, a partir de sua visĂŁo de futuro, da anĂĄlise dos ambientes interno e externo e da sua missĂŁo institucional formula suas estratĂ©gias, as desdobra em planos de aĂ§ĂŁo de curto e longo prazos e acompanha a sua implementaĂ§ĂŁo, visando o atendimento de sua missĂŁo e a satisfaĂ§ĂŁo das partes interessadas.',NULL,'0'),
('11','2','3','CidadĂŁo','60','Este critĂ©rio examina como a organizaĂ§ĂŁo, no cumprimento das suas competĂȘncias institucionais, identifica os cidadĂŁos usuĂĄrios dos seus serviĂ§os e produtos, conhece suas necessidades e avalia a sua capacidade de atendĂȘ-las, antecipando-se a elas. Aborda tambĂ©m como ocorre a divulgaĂ§ĂŁo de seus serviĂ§os, produtos e aĂ§Ă”es para fortalecer sua imagem institucional e como a organizaĂ§ĂŁo estreita o relacionamento com seus cidadĂŁos-usuĂĄrios, medindo a sua satisfaĂ§ĂŁo e implementando e promovendo aĂ§Ă”es de melhoria.',NULL,'0'),
('12','2','4','Sociedade','60','Este critĂ©rio examina como a organizaĂ§ĂŁo aborda suas responsabilidades perante a sociedade e as comunidades diretamente afetadas pelos seus processos, serviĂ§os e produtos e como estimula a cidadania. Examina, tambĂ©m, como a organizaĂ§ĂŁo atua em relaĂ§ĂŁo Ă s polĂ­ticas pĂșblicas do seu setor e como estimula o controle social de suas atividades pela Sociedade e o comportamento Ă©tico.',NULL,'0'),
('13','2','5','InformaĂ§ĂŁo e Conhecimento','60','Este critĂ©rio examina a gestĂŁo das informaĂ§Ă”es, incluindo a obtenĂ§ĂŁo de informaĂ§Ă”es comparativas pertinentes. TambĂ©m examina como a organizaĂ§ĂŁo identifica, desenvolve, mantĂ©m e protege os seus conhecimentos.',NULL,'0'),
('14','2','6','Pessoas','90','Este critĂ©rio examina os sistemas de trabalho da organizaĂ§ĂŁo, incluindo a organizaĂ§ĂŁo do trabalho, a estrutura de cargos, os processos relativos Ă  seleĂ§ĂŁo e contrataĂ§ĂŁo de pessoas, assim como a gestĂŁo do desempenho de pessoas e equipes. TambĂ©m examina os processos relativos Ă  capacitaĂ§ĂŁo e ao desenvolvimento das pessoas e como a organizaĂ§ĂŁo promove a qualidade de vida das pessoas interna e externamente ao ambiente de trabalho.',NULL,'0'),
('15','2','7','Processos','110','Este critĂ©rio examina como a organizaĂ§ĂŁo gerencia, analisa e melhora os processos finalĂ­sticos e os processos de apoio. TambĂ©m examina como a organizaĂ§ĂŁo gerencia o processo de suprimento, destacando o desenvolvimento da sua cadeia de suprimento. O critĂ©rio aborda como a organizaĂ§ĂŁo gerencia os seus processos orĂ§amentĂĄrios e financeiros, visando o seu suporte.',NULL,'0'),
('16','2','8','Resultados','450','Este critĂ©rio examina os resultados da organizaĂ§ĂŁo, abrangendo os orĂ§amentĂĄrio-financeiros, os relativos aos cidadĂŁos-usuĂĄrios, Ă  sociedade, Ă s pessoas, aos processos finalĂ­sticos e processos de apoio, assim como aos relativos ao suprimento. A avaliaĂ§ĂŁo dos resultados inclui a anĂĄlise da tendĂȘncia e do nĂ­vel atual de desempenho, pela verificaĂ§ĂŁo do atendimento dos nĂ­veis de expectativa das partes interessadas e pela comparaĂ§ĂŁo com o desempenho de outras organizaĂ§Ă”es.',NULL,'1'),
('17','3','1','LideranĂ§a','60','Este critĂ©rio examina a governanĂ§a da organizaĂ§ĂŁo, incluindo aspectos relativos Ă  transparĂȘncia, eqĂŒidade, prestaĂ§ĂŁo de contas e responsabilidade corporativa. TambĂ©m examina como Ă© exercida a lideranĂ§a, incluindo temas como o controle dos padrĂ”es de trabalho e aprendizado. O critĂ©rio aborda a anĂĄlise do desempenho da organizaĂ§ĂŁo enfatizando a comparaĂ§ĂŁo com o de outras organizaĂ§Ă”es e o atendimento aos requisitos das partes interessadas.',NULL,'0'),
('18','3','2','EstratĂ©gias e planos','35','Este critĂ©rio examina o processo de formulaĂ§ĂŁo das estratĂ©gias, enfatizando a anĂĄlise do mercado de atuaĂ§ĂŁo e do macroambiente. TambĂ©m examina o processo de implementaĂ§ĂŁo das estratĂ©gias, incluindo a definiĂ§ĂŁo de indicadores, o desdobramento das metas e planos para as ĂĄreas da organizaĂ§ĂŁo e o acompanhamento dos ambientes internos e externos.',NULL,'0'),
('19','3','3','Clientes','35','Este critĂ©rio examina como a organizaĂ§ĂŁo segmenta o mercado e como identifica e trata as necessidades e expectativas dos clientes e dos mercados; divulga seus produtos e marcas; e estreita seu relacionamento com os clientes. TambĂ©m examina como a organizaĂ§ĂŁo avalia a satisfaĂ§ĂŁo e insatisfaĂ§ĂŁo dos clientes.',NULL,'0'),
('20','3','4','Sociedade','30','Este critĂ©rio examina o cumprimento da responsabilidade socioambiental pela organizaĂ§ĂŁo, destacando aĂ§Ă”es voltadas para o desenvolvimento sustentĂĄvel. TambĂ©m examina como a organizaĂ§ĂŁo promove o desenvolvimento social, incluindo a realizaĂ§ĂŁo ou apoio a projetos sociais ou voltados para o desenvolvimento nacional, regional, local ou setorial.',NULL,'0'),
('21','3','5','InformaĂ§Ă”es e conhecimento','30','Este critĂ©rio examina a gestĂŁo das informaĂ§Ă”es, incluindo a obtenĂ§ĂŁo de informaĂ§Ă”es comparativas pertinentes. TambĂ©m examina como a organizaĂ§ĂŁo identifica, desenvolve, mantĂ©m e protege os seus ativos intangĂ­veis.',NULL,'0'),
('22','3','6','Pessoas','45','Este critĂ©rio examina os sistemas de trabalho da organizaĂ§ĂŁo, incluindo a organizaĂ§ĂŁo do trabalho, os processos relativos Ă  seleĂ§ĂŁo e contrataĂ§ĂŁo de pessoas, assim como o estĂ­mulo ao desempenho de pessoas. TambĂ©m examina os processos relativos Ă  capacitaĂ§ĂŁo e desenvolvimento das pessoas e como a organizaĂ§ĂŁo promove a construĂ§ĂŁo do ambiente propĂ­cio Ă  qualidade de vida das pessoas, interna e externamente ao ambiente de trabalho.',NULL,'0'),
('23','3','7','Processos','60','Este critĂ©rio examina como a organizaĂ§ĂŁo identifica, gerencia, analisa e melhora os processos principais do negĂłcio e os processos de apoio. TambĂ©m examina como a organizaĂ§ĂŁo gerencia o processo de relacionamento com os fornecedores e conduz a gestĂŁo dos processos econĂŽmico-financeiros, visando Ă  sustentabilidade econĂŽmica do negĂłcio.',NULL,'0'),
('24','3','8','Resultados','205','Este critĂ©rio examina os resultados relevantes da organizaĂ§ĂŁo, abrangendo os econĂŽmico-financeiros e os relativos aos clientes e mercados, sociedade, pessoas, processos principais do negĂłcio e de apoio, assim como os relativos ao relacionamento com fornecedores.',NULL,'1'),
('25','4','1','LideranĂ§a','55','Este critĂ©rio examina a governanĂ§a pĂșblica e a governabilidade da organizaĂ§ĂŁo, incluindo aspectos relativos Ă  transparĂȘncia, equidade, prestaĂ§ĂŁo de contas e responsabilidade corporativa. TambĂ©m examina como Ă© exercida a lideranĂ§a, incluindo temas como mudanĂ§a cultural e implementaĂ§ĂŁo do sistema de gestĂŁo da organizaĂ§ĂŁo. O critĂ©rio aborda a anĂĄlise do desempenho da organizaĂ§ĂŁo enfatizando a comparaĂ§ĂŁo com o desempenho de outras organizaĂ§Ă”es e a avaliaĂ§ĂŁo do ĂȘxito das estratĂ©gias.',NULL,'0'),
