INSERT INTO pratica_regra_campo VALUES
('1','4','pratica_adequada','AdequaĂ§ĂŁo','Atendimento consistente aos requisitos propostos, i.e., realizaĂ§ĂŁo das funĂ§Ă”es relativas aos processos gerenciais requeridos, com mecanismo de controle, atendendo a eventuais especifcidades requeridas e apresentando eventuais informaĂ§Ă”es e destaques solicitados, de forma adequada ao perfil da organizaĂ§ĂŁo.','0'),
('2','4','pratica_proativa','Proativade','Capacidade de antecipar-se aos fatos, a fim de prevenir a ocorrĂȘncia de situaĂ§Ă”es potencialmente indesejĂĄveis e aumentar a confanĂ§a e a previsibilidade dos processos gerenciais.','0'),
('3','4','pratica_continuada','Continuidade','UtilizaĂ§ĂŁo periĂłdica e ininterrupta, considerando-se a realizaĂ§ĂŁo de pelo menos um ciclo completo.','0'),
('4','4','pratica_abrange_pertinentes','AbrangĂȘncia','Cobertura ou escopo suficientes, horizontal ou vertical, conforme pertinente a cada processo gerencial requerido pelas ĂĄreas, processos, produtos ou partes interessadas, considerando-se o perfil da organizaĂ§ĂŁo e estratĂ©gias.','0'),
('5','4','pratica_refinada','Refinamento','AperfeiĂ§oamento decorrente dos processos de melhoria e inovaĂ§ĂŁo.','0'),
('6','4','pratica_melhoria_aprendizado','Melhorias pelo aprendizado','Melhorias implementadas foram decorrentes do aprendizado, ao se girar o ciclo PDCA.','0'),
('7','4','pratica_coerente','CoerĂȘncia','RelaĂ§ĂŁo harmĂŽnica com as estratĂ©gias e objetivos da organizaĂ§ĂŁo, incluindo valores e princĂ­pios.','0'),
('8','4','pratica_interrelacionada','Inter-relacionamento','implementaĂ§ĂŁo de modo complementar com outras prĂĄticas de gestĂŁo da organizaĂ§ĂŁo, onde apropriado.','0'),
('9','4','pratica_cooperacao','CooperaĂ§ĂŁo','ColaboraĂ§ĂŁo entre as ĂĄreas da organizaĂ§ĂŁo na implementaĂ§ĂŁo planejamento, execuĂ§ĂŁo, controle ou aperfeiĂ§oamento das prĂĄticas de gestĂŁo.','0'),
('10','4','pratica_indicador_relevante','RelevĂąncia','Grau em que o resultado apresentado sĂŁo importantes para a determinaĂ§ĂŁo do alcance dos objetivos estratĂ©gicos e operacionais da organizaĂ§ĂŁo.','1'),
('11','4','pratica_indicador_favoravel','TendĂȘncia favorĂĄvel','Grau em que o resultado relevante apresentados demonstram evoluĂ§ĂŁo favorĂĄvel ao longo de, pelo menos, trĂȘs Ășltimos perĂ­odos consecutivos. Esses perĂ­odos devem ser coerentes com ciclos de planejamento e de anĂĄlise do desempenho na organizaĂ§ĂŁo.','1'),
('12','4','pratica_indicador_superior','Competitivo','NĂ­veis de resultados superiores, no mercado ou setor de atuaĂ§ĂŁo, evidenciados por meio de referenciais comparativos pertinentes.','1'),
('13','4','pratica_indicador_lider','Lider','PosiĂ§ĂŁo de lideranĂ§a de mercado, ou do setor de atuaĂ§ĂŁo, em que as forĂ§as do macroambiente criam condiĂ§Ă”es similares de competiĂ§ĂŁo, por clientes, oportunidades ou recursos de qualquer natureza, na regiĂŁo de atuaĂ§ĂŁo.','1'),
('14','6','pratica_adequada','AdequaĂ§ĂŁo','Atendimento consistente aos requisitos propostos, i.e., realizaĂ§ĂŁo das funĂ§Ă”es relativas aos processos gerenciais requeridos, com mecanismo de controle, atendendo a eventuais especifcidades requeridas e apresentando eventuais informaĂ§Ă”es e destaques solicitados, de forma adequada ao perfil da organizaĂ§ĂŁo.','0'),
