('106','12','pratica_cooperacao_partes','CooperaĂ§ĂŁo com interessados','<p>HĂĄ cooperaĂ§ĂŁo com as partes interessadas mais impactadas, no desenvolvimentou ou realizaĂ§ĂŁo da prĂĄtica de gestĂŁo.</p>','0'),
('107','12','pratica_coerente','CoerĂȘncia','<p>Existe coerĂȘncia com os valores, princĂ­pios, estratĂ©gias e objetivos organizacionais, na realizaĂ§ĂŁo da prĂĄtica de gestĂŁo.</p>','0'),
('108','12','pratica_incoerente','IncoerĂȘncia grave','<p>Existe incoerĂȘncia grave entre os valores, princĂ­pios, estratĂ©gias e objetivos organizacionais, na realizaĂ§ĂŁo da prĂĄtica de gestĂŁo.</p>','0'),
('109','12','pratica_indicador_relevante','RelevĂąncia','<p>O resultado esperado para avaliar o desempenho Ă© demonstrado por meio de indicador compatĂ­vel com o Perfil, estratĂ©gias e processos gerenciais da organizaĂ§ĂŁo.</p>','1'),
('110','12','pratica_indicador_complemento','Complementos','<p>A classe e estratificaĂ§ĂŁo do resultado, quando requerida, Ă© suficientemente demonstrada.</p>','1'),
('111','12','pratica_indicador_estrategico','EstratĂ©gico','<p>O resultado estratĂ©gico necessĂĄrio Ă© demonstrados por meio deste indicador.</p>','1'),
('112','12','pratica_indicador_favoravel','TendĂȘncia favorĂĄvel','<p>Os resultados exigidos e esperados para avaliar o desempenho demonstram melhoria ou estabilizaĂ§ĂŁo em nĂ­vel aceitĂĄvel, nos trĂȘs Ășltimos exercĂ­cios ou ciclos de avaliaĂ§ĂŁo.</p>','1'),
('113','12','pratica_indicador_estrategico_favoravel','EstratĂ©gico com tendĂȘncia favorĂĄvel','<p>O resultado estratĂ©gico demonstra melhoria ou estabilizaĂ§ĂŁo em nĂ­vel aceitĂĄvel.</p>','1'),
('114','12','pratica_indicador_superior','Competitivo','<p>O resultados exigido e esperado para avaliar o desempenho, que permitem comparaĂ§ĂŁo com referencial comparativo pertinente, demonstra, no Ășltimo exercĂ­cio ou ciclo, ser equivalente ou superior a esse referencial.</p>','1'),
('115','12','pratica_indicador_estrategico_superior','EstratĂ©gico competitivo','<p>O resultado estratĂ©gico demonstra ser equivalente ou superior ao referencial comparativo pertinente.</p>','1'),
('116','12','pratica_indicador_lider','LideranĂ§a','<p>Resultado estratĂ©gico em nĂ­vel de lidereanĂ§a no setor ou no mercado.</p>','1'),
('117','12','pratica_indicador_estrategico_lider','EstratĂ©gico Lider','<p>Resultado estratĂ©gico em nĂ­vel de lideranĂ§a no setor ou no mercado.</p>','1'),
('118','12','pratica_indicador_excelencia','ExcelĂȘncia','<p>HĂĄ demonstraĂ§ĂŁo de o indicador estratĂ©gico estar em nĂ­vel de referencial de excelĂȘncia no setor ou no mercado.</p>','1'),
('119','12','pratica_indicador_estrategico_excelencia','EstratĂ©gico Excelente','<p>Resultado estratĂ©gico em nĂ­vel de referencial de excelĂȘncia no setor ou no mercado.</p>','1'),
('120','12','pratica_indicador_atendimento','Atendimento aos requisitos','<p>O indicador demonstra, no Ășltimo exercĂ­cio ou ciclo, operacionais, suficientes para avaliar o desempenho relativo a requisitos de partes interessadas, em termos de nĂ­vel alcanĂ§ado ou superado, ou de melhoria esperada obtida.</p>','1'),
('121','12','pratica_indicador_estrategico_atendimento','EstratĂ©gico atendimento','<p>Resultado estratĂ©gico ser equivalente ou superior ao referencial comparativo pertinente.</p>','1'),
('122','13','pratica_adequada','AdequaĂ§ĂŁo','<p>Atendimento aos requisitos do item, incluindo os mĂ©todos de controle, de forma apropriada ao perfil da organizaĂ§ĂŁo.</p>','0'),
('123','13','pratica_proativa','Proativade','<p>Capacidade de se antecipar aos fatos, a fim de prevenir a ocorrĂȘncia de situaĂ§Ă”es potencialmente indesejĂĄveis e aumentar a confianĂ§a e a previsibilidade dos processos. Ă importante que a avaliaĂ§ĂŁo desse fator sĂł considere as prĂĄticas de gestĂŁo que efetivamente podem assumir a condiĂ§ĂŁo de proativas e reativas. Muitas prĂĄticas de gestĂŁo sĂŁo adequadas, mas nĂŁo sĂŁo proativas ou reativas.</p>','0'),
('124','13','pratica_abrange_pertinentes','DisseminaĂ§ĂŁo','<p>ImplementaĂ§ĂŁo, horizontal e vertical, pelas ĂĄreas, processos, produtos e/ou pelas partes interessadas, se pertinente ao item, considerando-se o perfil da organizaĂ§ĂŁo.</p>','0'),
('125','13','pratica_continuada','Continuidade','<p>UtilizaĂ§ĂŁo periĂłdica e ininterrupta da prĂĄtica de gestĂŁo, considerando, pelo menos, um ciclo completo realizado.</p>','0'),
('126','13','pratica_refinada_implantacao','Melhoria sendo implantada','<p>HĂĄ melhoria sendo implantada na prĂĄtica de gestĂŁo.</p>','0'),
('127','13','pratica_refinada','Refinamento','<p>Apresenta aperfeiĂ§oamento (refinamento) decorrente do processo de melhoria.</p>','0'),
('128','13','pratica_arte','Estado de arte','<p>Em estĂĄgio avanĂ§ado de refinamento, o processo gerencial atendidos por prĂĄtica de gestĂŁo deve espelhar o estado da arte.</p>','0'),
('129','13','pratica_inovacao','InovaĂ§ĂŁo','<p>Em estĂĄgios avanĂ§ados de refinamento, os processos gerenciais atendidos por prĂĄticas de gestĂŁo devem incorporar alguma inovaĂ§ĂŁo.</p>','0'),
('130','13','pratica_coerente','CoerĂȘncia','<p>PrĂĄtica de gestĂŁo alinhada com as estratĂ©gias e os objetivos da organizaĂ§ĂŁo.</p>','0'),
('131','13','pratica_interrelacionada','Inter-relacionamento','<p>ImplementaĂ§ĂŁo de modo complementar com outras prĂĄticas de gestĂŁo da organizaĂ§ĂŁo, quando apropriado.</p>','0'),
('132','13','pratica_cooperacao','CooperaĂ§ĂŁo','<p>ColaboraĂ§ĂŁo entre as ĂĄreas da organizaĂ§ĂŁo e entre a organizaĂ§ĂŁo na implementaĂ§ĂŁo das prĂĄticas de gestĂŁo.</p>','0'),
('133','13','pratica_cooperacao_partes','CooperaĂ§ĂŁo com as partes','<p>ColaboraĂ§ĂŁo com as partes interessadas na implementaĂ§ĂŁo das prĂĄticas de gestĂŁo.</p>','0'),
('134','13','pratica_indicador_relevante','Relevancia','<p>Refere-se Ă  importĂąncia do resultado para determinaĂ§ĂŁo do alcance dos objetivos estratĂ©gicos e principais objetivos operacionais da organizaĂ§ĂŁo.</p>','1'),
('135','13','pratica_indicador_favoravel','TendĂȘncia favorĂĄvel','<p>Refere-se ao comportamento do resultado ao longo do tempo, devendo ser favorĂĄvel.</p>','1'),
('136','13','pratica_indicador_tendencia','Com tendĂȘncia','<p>Refere-se ao comportamento do resultado ao longo do tempo.</p>','1'),
('137','13','pratica_indicador_superior','Superior ao referencial','<p>Refere-se ao grau em que o resultado organizacionl apresenta comparado com o desempenho de outra organizaĂ§ĂŁo considerada como referencial pertinente.</p>','1'),
('138','13','pratica_indicador_atendimento','Atendimento dos interessados','<p>NĂ­veis de resultados que demonstram o atendimento aos principais requisitos relacionados com necessidades e expectativas de partes interessadas.</p>','1'),
('139','13','pratica_indicador_lider','Lider','<p>PosiĂ§ĂŁo de lideranĂ§a de mercado, ou do setor de atuaĂ§ĂŁo, em que as forĂ§as do macroambiente criam condiĂ§Ă”es similares de competiĂ§ĂŁo, por clientes, oportunidades ou recursos de qualquer natureza, na regiĂŁo de atuaĂ§ĂŁo.</p>','1'),
('140','13','pratica_indicador_excelencia','ExcelĂȘncia','<p>O resultado apresentado denota a organizaĂ§ĂŁo ser referencial de excelĂȘncia.</p>','1');
